{"procName":"dbo.tr_dondathang_chitiet2_update","body":"CREATE PROCEDURE [dbo].[TR_DONDATHANG_CHITIET2_UPDATE]
(
	@id int,	@id_maddh int,	@maddh nvarchar(200),	@masp nvarchar(MAX),	@chitiet nvarchar(MAX),	@tenchitiet nvarchar(MAX),	@soluong decimal(18, 3),	@dvt nvarchar(50),	@sl_danhan decimal(18, 3),	@sl_conlai decimal(18, 3),	@dongia decimal(18, 3),	@thanhtien decimal(18, 3),	@loaitien nvarchar(50),	@donhang nvarchar(MAX),	@ghichu nvarchar(MAX),	@hoanthanh_htr bit,	@create_date datetime,	@create_by nvarchar(50),	@update_by nvarchar(50),	@update_date datetime,	@active bit,	@id_maddhid nchar(10),	@id_maddhmaddh nvarchar(200),	@maddhid nchar(10),	@maddhmaddh nchar(10),	@dayy float,	@rong float,	@dai float,	@nguyenlieu nvarchar(50),	@ngaycangiao datetime,	@sophieu_dexuat nvarchar(500),	@dongia_m3 float,	@iCreatedCard bit,	@iPrintedCard bit,	@fsc_id int,
	@tygia decimal(18, 3) = null
)
AS
BEGIN
	UPDATE tr_dondathang_chitiet2
	SET id_maddh = @id_maddh,		maddh = @maddh,		masp = @masp,		chitiet = @chitiet,		tenchitiet = @tenchitiet,		soluong = @soluong,		dvt = @dvt,		sl_danhan = @sl_danhan,		sl_conlai = @sl_conlai,		dongia = @dongia,		thanhtien = @thanhtien,		loaitien = @loaitien,		donhang = @donhang,		ghichu = @ghichu,		hoanthanh_htr = @hoanthanh_htr,		update_by = @update_by,		update_date = @update_date,		active = @active,		id_maddhid = @id_maddhid,		id_maddhmaddh = @id_maddhmaddh,		maddhid = @maddhid,		maddhmaddh = @maddhmaddh,		dayy = @dayy,		rong = @rong,		dai = @dai,		nguyenlieu = @nguyenlieu,		ngaycangiao = @ngaycangiao,		sophieu_dexuat = @sophieu_dexuat,		dongia_m3 = @dongia_m3,		iCreatedCard = @iCreatedCard,		iPrintedCard = @iPrintedCard,		fsc_id = @fsc_id,
		tygia = @tygia
	WHERE id = @id

	DECLARE @idChiTiet2 nvarchar(max);
	DECLARE @tongsoluong decimal(18, 3);
	SELECT @idChiTiet2 = idChiTiet2 FROM tr_dondathang_chitiet2 WHERE id = @id;
	SELECT @tongsoluong = SUM(soluong) FROM tr_dondathang_chitiet2 WHERE idChiTiet2 = @idChiTiet2;

	UPDATE tr_dondathang_chitiet
	SET soluong = @tongsoluong,
		sl_conlai = @tongsoluong - sl_danhan
	WHERE idChiTiet2 = @idChiTiet2

END
